/* CSS */

/* Style for the Test Function message (lightblue bar) */
#cwp-function-test-message {
	background-color: lightblue;
	color: black;
	padding: 15px;
	margin-top: 20px;
	text-align: center;
	font-weight: bold;
	border: 1px solid darkblue;
}

/* Style for the Test Script message (lightgreen bar) */
#cwp-script-test-message {
  /* Original styles translated to CSS */
  background-color: lightgreen;
  color: black;
  padding: 15px;
  margin-top: 20px;
  text-align: center;
  font-weight: bold;
  border: 1px solid darkgreen;

  /* Keep any additional styles you added, like: */
  font-style: italic;
  text-shadow: 1px 1px 1px #ccc;
  /* If you had !important on border/padding/margin, you can likely remove it now */
}
